SET client_encoding TO 'UTF8';

SET check_function_bodies = false;

DROP TRIGGER IF EXISTS tbiu_sc_atm_send_detail ON sc_atm_send_detail CASCADE;
CREATE OR REPLACE FUNCTION trigger_fct_tbiu_sc_atm_send_detail() RETURNS trigger AS $BODY$
BEGIN
  if coalesce(NEW.seq_no::text, '') = '' or NEW.seq_no = 0 then
    select max(seq_no) into STRICT NEW.seq_no
    from sc_atm_send_detail
    where (item_no = NEW.item_no)
    and (operate_date = NEW.operate_date);
    NEW.seq_no := coalesce(NEW.seq_no,0) + 1;
  end if;

  if coalesce(NEW.send_last_no::text, '') = '' or NEW.send_last_no = 0 then
    if length(trim(both NEW.item_ref_no)) > 0 then
      if NEW.trans_type = 'LON' then
        select max(seq_no) into STRICT NEW.send_last_no
        from sc_lon_m_loan_card_detail
        where (loan_contract_no = NEW.item_ref_no);
      elsif NEW.trans_type = 'DEP' then
        select max(seq_no) into STRICT NEW.send_last_no
        from sc_dep_m_creditor_item
        where (deposit_account_no = NEW.item_ref_no);
      end if;
    end if;
  end if;

  if coalesce(NEW.trans_type::text, '') = '' then
    CALL spa_dberror('E28:trans_type is null');
  else
    if coalesce(OLD.trans_type::text, '') = '' or OLD.trans_type <> NEW.trans_type then
      if NEW.trans_type not in ('LON','DEP') then
        CALL spa_dberror('E32: trans_type not in case('||trim(both NEW.trans_type)||')');
      end if;
    end if;
  end if;

  if coalesce(NEW.trans_amount::text, '') = '' then NEW.trans_amount := 0;end if;
  if coalesce(NEW.approve_amount::text, '') = '' then NEW.approve_amount := 0;end if;
  if coalesce(NEW.send_last_no::text, '') = '' then NEW.send_last_no := 0;end if;
  if coalesce(NEW.bank_confirm::text, '') = '' or NEW.bank_confirm =' ' then NEW.bank_confirm :='0';end if;
  if coalesce(NEW.coop_confirm::text, '') = '' or NEW.coop_confirm =' ' then NEW.coop_confirm :='0';end if;

  --Niorn 2024-10-01 MWA ไม่ให้บันทึกถ้าไม่เลขที่บัญชี
--  if :new.account_no is null or :new.account_no = '' or :new.account_no = ' '  then 
--    spa_dberror('T44:TBIU_SC_ATM_SEND_DETAIL กรุณาระบุบัญชีธนาคาร');
--  end if;
RETURN NEW;
end
$BODY$
 LANGUAGE 'plpgsql' SECURITY DEFINER;
-- REVOKE ALL ON FUNCTION trigger_fct_tbiu_sc_atm_send_detail() FROM PUBLIC;

CREATE TRIGGER tbiu_sc_atm_send_detail
	BEFORE INSERT OR UPDATE ON sc_atm_send_detail FOR EACH ROW
	EXECUTE PROCEDURE trigger_fct_tbiu_sc_atm_send_detail();

